        initvalu_temp[i] = initvalu[i] + h * (b61*finavalu_temp[0][i] + b64*finavalu_temp[3][i] + b65*finavalu_temp[4][i]);
    }
    evaluate_deriv_cuda(timeinst+a6*h, initvalu_temp, parameter, finavalu_temp[5], com, d_initvalu, d_finavalu, d_params, d_com);

    for(int i=0; i<EQUATIONS; i++){
        initvalu_temp[i] = initvalu[i] + h * (b71*finavalu_temp[0][i] + b74*finavalu_temp[3][i] + b75*finavalu_temp[4][i] + b76*finavalu_temp[5][i]);
    }
    evaluate_deriv_cuda(timeinst+a7*h, initvalu_temp, parameter, finavalu_temp[6], com, d_initvalu, d_finavalu, d_params, d_com);

    for(int i=0; i<EQUATIONS; i++){
        initvalu_temp[i] = initvalu[i] + h * (b81*finavalu_temp[0][i] + b85*finavalu_temp[4][i] + b86*finavalu_temp[5][i] + b87*finavalu_temp[6][i]);
    }
    evaluate_deriv_cuda(timeinst+a8*h, initvalu_temp, parameter, finavalu_temp[7], com, d_initvalu, d_finavalu, d_params, d_com);

    for(int i=0; i<EQUATIONS; i++){
        initvalu_temp[i] = initvalu[i] + h * (b91*finavalu_temp[0][i] + b94*finavalu_temp[3][i] + b95*finavalu_temp[4][i] + b96*finavalu_temp[5][i] + b97*finavalu_temp[6][i] + b98*finavalu_temp[7][i]);
    }
    evaluate_deriv_cuda(timeinst+a9*h, initvalu_temp, parameter, finavalu_temp[8], com, d_initvalu, d_finavalu, d_params, d_com);

    for(int i=0; i<EQUATIONS; i++){
        initvalu_temp[i] = initvalu[i] + h * (b10_1*finavalu_temp[0][i] + b10_4*finavalu_temp[3][i] + b10_5*finavalu_temp[4][i] + b10_6*finavalu_temp[5][i] + b10_7*finavalu_temp[6][i] + b10_8*finavalu_temp[7][i] + b10_9*finavalu_temp[8][i]);
    }
    evaluate_deriv_cuda(timeinst+a10*h, initvalu_temp, parameter, finavalu_temp[9], com, d_initvalu, d_finavalu, d_params, d_com);

    for(int i=0; i<EQUATIONS; i++){
        initvalu_temp[i] = initvalu[i] + h * (b11_1*finavalu_temp[0][i] + b11_4*finavalu_temp[3][i] + b11_5*finavalu_temp[4][i] + b11_6*finavalu_temp[5][i] + b11_7*finavalu_temp[6][i] + b11_8*finavalu_temp[7][i] + b11_9*finavalu_temp[8][i] + b11_10*finavalu_temp[9][i]);
    }
    evaluate_deriv_cuda(timeinst+h, initvalu_temp, parameter, finavalu_temp[10], com, d_initvalu, d_finavalu, d_params, d_com);

    for(int i=0; i<EQUATIONS; i++){
        initvalu_temp[i] = initvalu[i] + h * (b12_1*finavalu_temp[0][i] + b12_6*finavalu_temp[5][i] + b12_7*finavalu_temp[6][i] + b12_8*finavalu_temp[7][i] + b12_9*finavalu_temp[8][i] + b12_10*finavalu_temp[9][i]);
    }
    evaluate_deriv_cuda(timeinst, initvalu_temp, parameter, finavalu_temp[11], com, d_initvalu, d_finavalu, d_params, d_com);

    for(int i=0; i<EQUATIONS; i++){
        initvalu_temp[i] = initvalu[i] + h * (b13_1*finavalu_temp[0][i] + b13_4*finavalu_temp[3][i] + b13_5*finavalu_temp[4][i] + b13_6*finavalu_temp[5][i] + b13_7*finavalu_temp[6][i] + b13_8*finavalu_temp[7][i] + b13_9*finavalu_temp[8][i] + b13_10*finavalu_temp[9][i] + finavalu_temp[11][i]);
    }
    evaluate_deriv_cuda(timeinst+h, initvalu_temp, parameter, finavalu_temp[12], com, d_initvalu, d_finavalu, d_params, d_com);

    for(int i=0; i<EQUATIONS; i++){
        finavalu[i] = initvalu[i] + h * (c_1_11 * (finavalu_temp[0][i] + finavalu_temp[10][i])
                    + c6 * finavalu_temp[5][i]
                    + c_7_8 * (finavalu_temp[6][i] + finavalu_temp[7][i])
                    + c_9_10 * (finavalu_temp[8][i] + finavalu_temp[9][i]));
    }

    for(int i=0; i<EQUATIONS; i++){
        error[i] = fabsf(err_factor * (finavalu_temp[0][i] + finavalu_temp[10][i] - finavalu_temp[11][i] - finavalu_temp[12][i]));
    }
}

int solver(fp** y,
           fp* x,
           int xmax,
           fp* params,
           int mode) {

    (void)mode;

    fp err_exponent;
    fp last_interval;
    int error_flag;
    int outside;
    fp h;
    fp h_init;
    fp tolerance;
    int xmin;

    fp scale_min;
    fp scale_fina;
    fp* err = (fp *) malloc(EQUATIONS * sizeof(fp));
    fp* scale = (fp *) malloc(EQUATIONS * sizeof(fp));
    fp* yy = (fp *) malloc(EQUATIONS * sizeof(fp));

    fp *d_initvalu = NULL;
    fp *d_finavalu = NULL;
    fp *d_params = NULL;
    fp *d_com = NULL;

    int i, j, k;

    cudaMalloc((void**)&d_initvalu, EQUATIONS * sizeof(fp));
    cudaMalloc((void**)&d_finavalu, EQUATIONS * sizeof(fp));
    cudaMalloc((void**)&d_params, PARAMETERS * sizeof(fp));
    cudaMalloc((void**)&d_com, 3 * sizeof(fp));

    err_exponent = 1.0f / 7.0f;
    last_interval = 0.0f;
    h_init = 1.0f;
    h = h_init;
    xmin = 0;
    tolerance = 10.0f / (fp)(xmax-xmin);

    x[0] = 0.0f;

    if (xmax < xmin || h <= 0.0f){
        cudaFree(d_initvalu);
        cudaFree(d_finavalu);
        cudaFree(d_params);
        cudaFree(d_com);
        free(err);
        free(scale);
        free(yy);
        return -2;
    }

    if (xmax == xmin){
        cudaFree(d_initvalu);
        cudaFree(d_finavalu);
        cudaFree(d_params);
        cudaFree(d_com);
        free(err);
        free(scale);
        free(yy);
        return 0;
    }

    if (h > (xmax - xmin)) {
        h = (fp)xmax - (fp)xmin;
        last_interval = 1.0f;
    }

    for(k=1; k<=xmax; k++) {

        x[k] = (fp)(k-1);
        h = h_init;
        scale_fina = 1.0f;

        for (j = 0; j < ATTEMPTS; j++) {

            error_flag = 0;
            outside = 0;
            scale_min = MAX_SCALE_FACTOR;

            rkf78_step_cuda(x[k], h, y[k-1], y[k], err, params, d_initvalu, d_finavalu, d_params, d_com);

            for(i=0; i<EQUATIONS; i++){
                if(err[i] > 0.0f){
                    error_flag = 1;
                }
            }
            if (error_flag != 1) {
                scale_fina = MAX_SCALE_FACTOR;
                break;
            }

            for(i=0; i<EQUATIONS; i++){
                if(y[k-1][i] == 0.0f){
                    yy[i] = tolerance;
                }
                else{
                    yy[i] = fabsf(y[k-1][i]);
                }
                scale[i] = 0.8f * powf(tolerance * yy[i] / err[i], err_exponent);
                if(scale[i] < scale_min){
                    scale_min = scale[i];
                }
            }
            scale_fina = mymin(mymax(scale_min, MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

            for(i=0; i<EQUATIONS; i++){
                if (err[i] > (tolerance * yy[i])){
                    outside = 1;
                }
            }
            if (outside == 0){
                break;
            }

            h = h * scale_fina;

            if (h >= 0.9f) {
                h = 0.9f;
            }

            if (x[k] + h > (fp)xmax){
                h = (fp)xmax - x[k];
            }
            else if (x[k] + 0.5f * h + h > (fp)xmax){
                h = 0.5f * h;
            }
        }

        x[k] = x[k] + h;

        if (j >= ATTEMPTS) {
            cudaFree(d_initvalu);
            cudaFree(d_finavalu);
            cudaFree(d_params);
            cudaFree(d_com);
            free(err);
            free(scale);
            free(yy);
            return -1;
        }
    }

    cudaFree(d_initvalu);
    cudaFree(d_finavalu);
    cudaFree(d_params);
    cudaFree(d_com);

    free(err);
    free(scale);
    free(yy);

    (void)last_interval;
    return 0;
}

int main(int argc, char *argv []){

    long long time0;
    long long time1;
    long long time2;
    long long time3;
    long long time4;
    long long time5;

    time0 = get_time();

    long long memory;
    int i, j;
    int status;
    int mode;

    long workload;
    long xmax;

    fp*** y;
    fp** x;
    fp** params;

    int threads;

    if(argc!=5){
        printf("ERROR: %d is the incorrect number of arguments, the number of arguments must be 4\n", argc-1);
        return 0;
    }
    else{
        xmax = atoi(argv[1]);
        if(xmax<0){
            printf("ERROR: %ld is the incorrect end of simulation interval, use numbers > 0\n", xmax);
            return 0;
        }

        workload = atoi(argv[2]);
        if(workload<0){
            printf("ERROR: %ld is the incorrect number of instances of simulation, use numbers > 0\n", workload);
            return 0;
        }

        mode = 0;
        mode = atoi(argv[3]);
        if(mode != 0 && mode != 1){
            printf("ERROR: %d is the incorrect mode, it should be omitted or equal to 0 or 1\n", mode);
            return 0;
        }

        threads = atoi(argv[4]);
        if(threads<0){
            printf("ERROR: %d is the incorrect number of threads, use numbers > 0\n", threads);
            return 0;
        }
        (void)threads;
    }

    time1 = get_time();

    memory = workload*(xmax+1)*EQUATIONS*4;
    if(memory>1000000000){
        printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
        return 0;
    }

    y = (fp ***) malloc(workload * sizeof(fp **));
    for(i=0; i<workload; i++){
        y[i] = (fp**)malloc((1+xmax) * sizeof(fp*));
        for(j=0; j<(1+xmax); j++){
            y[i][j]= (fp *) malloc(EQUATIONS * sizeof(fp));
        }
    }

    x = (fp **) malloc(workload * sizeof(fp *));
    for(i=0; i<workload; i++){
        x[i]= (fp *)malloc((1+xmax) * sizeof(fp));
    }

    params = (fp **) malloc(workload * sizeof(fp *));
    for(i=0; i<workload; i++){
        params[i]= (fp *)malloc(PARAMETERS * sizeof(fp));
    }

    time2 = get_time();

    for(i=0; i<workload; i++){
        read((char*)"../../data/myocyte/y.txt", y[i][0], 91, 1, 0);
    }

    for(i=0; i<workload; i++){
        read((char*)"../../data/myocyte/params.txt", params[i], 16, 1, 0);
    }

    time3 = get_time();

    for(i=0; i<workload; i++){
        status = solver(y[i], x[i], xmax, params[i], mode);
        (void)status;
    }

    cudaDeviceSynchronize();

    time4 = get_time();

    for(i=0; i<workload; i++){
        for(j=0; j<(1+xmax); j++){
            free(y[i][j]);
        }
        free(y[i]);
    }
    free(y);

    for(i=0; i<workload; i++){
        free(x[i]);
    }
    free(x);

    for(i=0; i<workload; i++){
        free(params[i]);
    }
    free(params);

    time5 = get_time();

    printf("Time spent in different stages of the application:\n");
    printf("%.12f s, %.12f % : SETUP VARIABLES, READ COMMAND LINE ARGUMENTS\n", (float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time5-time0) * 100);
    printf("%.12f s, %.12f % : ALLOCATE MEMORY\n", (float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time5-time0) * 100);
    printf("%.12f s, %.12f % : READ DATA FROM FILES\n", (float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time5-time0) * 100);
    printf("%.12f s, %.12f % : RUN COMPUTATION\n", (float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time5-time0) * 100);
    printf("%.12f s, %.12f % : FREE MEMORY\n", (float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time5-time0) * 100);
    printf("Total time:\n");
    printf("%.12f s\n", (float) (time5-time0) / 1000000);

    return 0;
}
